window.__dh_data["kk"] = {
  "": "Content-Type: text/plain; charset=UTF-8\nContent-Transfer-Encoding: 8bit\n",
  "title": "Дхаммапада",
  "chaps": "Бөлімдер",
  "fontsize": "Қаріп өлшемі",
  "chap1": "Қос Жолдар",
  "1": "Дхамма тек ақылмен ғана байланысты, оның негізі – ақыл, ол ақылдан жаратылған. Егер кімде-кім арам ақылмен іс істесе, не сөз айтса, арбаның дөңгелегі өзін сүйреткен көліктен қалмайтыны сияқты, оның артынан бақытсыздық та қалмайды.",
  "2": "Дхамма тек ақылмен ғана байланысты, оның негізі – ақыл, ол ақылдан жаратылған. Егер кімде-кім таза, кіршіксіз ақылмен іс істесе, не сөз айтса, оның артынан өзінің көлеңкесі сияқты бақыт та қалмайды.",
  "3": "'Ол мені масқаралады, ол мені ұрды, ол менің үстімнен билеп кетті, ол менікін түгел ұрлап кетті'. Кімде-кімнің ойынан осындай пікір кетпесе, оның бойынан әлдекімді жеккөрушілік кетпейді.",
  "4": "'Ол мені масқаралады, ол мені ұрды, ол менің үстімнен билеп кетті, ол менікін түгел ұрлап кетті'. Кімде-кімнің ойынан осындай пікір кетсе, оның бойынан әлдекімді жеккөрушілік ада болады.",
  "5": "Бұл дүниеде ешқашанда күншілдікті күншілдік тоқтата алмайды, күншілдік еш жерде болмаса ғана, күншілдік жойылар еді. Мәңгілік дхамма дегеніміз осы.",
  "6": "Біздің осы жерде өміріміз аяқталатынын кез-келген адам біле бермейді-ау. Егерде осыны білер болсақ, біздің басқа біреулермен айтысып, дауласа беруіміз мүлдем тоқталар еді ғой.",
  "7": "Кімде-кім өзінің нәпсісін неғұрлым қанағаттандыра түсудің қамын ойласа, өзінің сезімін ауыздықтай алмаса, тамаққа қомағай, жалқау, батылсыздау болса, ұйтқыған құйынның түбі бос ағашты құлатып, талқандап кететіні сияқты, оны Мара талқандап кетер еді.",
  "8": "Кімде-кім өзінің нәпсісін неғұрлым қанағаттандыра түсудің қамын ойламаса, өзінің сезімін ауыздықтай білсе, тамаққа қанағатшыл, әр кез батыл, бірбеткей болса, күшті құйынның құз, жартасты тауды құлата алмайтыны сияқты, оны Мара талқандап кете алмас еді.",
  "9": "Кімде-кім тазаламай, шындықты түсінбей, өзін әр нәрседен тежеп ұстамай, сарғайған киім киіп жүрсе, ол сары киім киіп жүруге лайықты емес.",
  "10": "Кімде-кім үсті-басын мұнтаздай таза ұстап, әр нәрсеге әр кезде рахымшылық көрсетіп жүрсе, шындықты шын мәнінде түсініп, өзін өзі тежеп ұстап жүрсе, ол сары киім киіп жүруге лайықты болмақ.",
  "11": "Істің мәнісіне жетпей жалтақтап тұратын, мәнсіз нәрседен өзінше мән шығарып жүретін адамдар ешқашан істің шын мәнісіне жете алмайды, өйткені ондайлардың үлесіне жалған ниет қана тиесілі.",
  "12": "Мәндіні мәнді деп, мәнсізді мәнсіз деп, істің мәнісін шынайы түсінетін адамға шынайы ниет тиесілі.",
  "13": "Төбесі жаман жабылған үйге жаңбыр өтіп кететіні сияқты, нашар дамыған ақылды да тиымсыз көрсеқызар құмарлық билеп алады.",
  "14": "Төбесі жақсы жабылған үйден жаңбыр өтпейтіні сияқты, жақсы дамыған ақылды көрсеқызар құмарлық билей алмайды.",
  "15": "Бұл өмірде зарлап жүрген адам ол дүниеде де зарлап қалады. Ісі арам адам екі дүниеде де зарлап қалады. Ол өзінің істеген зұлымдық ісі үшін іштей азап тартады, зарлап жүреді.",
  "16": "Бұл өмірде жайнап жүрген адам ол дүниеде де жайнап жүреді. Істегені тек жақсылық болған адам екі дүниеде де жайнап жүреді. Ол өзінің жақсылық істерін көріп қуанады да жайнап жүреді.",
  "17": "Бұл өмірде азап тартқан адам ол дүниеде де азап тартады. Зұлымдық істеген адам екі дүниеде де азап тартады. 'Зұлымдықта мен істедім' – деп азап тартады. Ал, басына іс түскен күні одан әрі азап тартады.",
  "18": "Бұл өмірде шаттанып жүрген адам ол дүниеде де шаттанып жүреді. 'Жақсылықты мен істедім' – деп шаттанып жүреді. Ал, бақытқа қолы жеткен күні одан әрі шаттанады.",
  "19": "Егер бір адам Кітап сөзіне қатты иланып, бірақ үнемі мұңды күйде жүрсе, оны өзі жайып жүрген малы басқанікі деп ойлайтын бақташыға баламаған жөн. Ол адам қасиетті адам қатарына жатпайды.",
  "20": "Егер бір адам Кітапқа аз қарап, бірақ дхамма жолымен жүрсе, нәпсіге бой алдырмаса күншілдік пен надандықтан аулақ болса, тек шынайы біліммен, асыл ақылмен қаруланып, бұл дүниемен де, ол дүниемен де ісі жоқ болса, міне осы адам қасиетті адам қатарына жатады.",
  "chap2": "Парасаттылық",
  "21": "Салмақтылық – мәңгі жасаушылыққа апарар жол. Жеңіл ойлылық - өлімге апарар жол. Салмақты адам өлмейді. Жеңіл ойлылар өлілерге ұқсас.",
  "22": "Осыны ұққан ақылдылар – салмақтылар. Салмақтылықтан олар өз қуанышын табады. Мейірімділік мәресінде масайрайды олар.",
  "23": "Ойлылар, табандылар қашанда бекем, кемеңгер. Олар ешкімге тәуелсіз, еркін, теңдессіз, сондықтан ондайлар Нирванаға жетеді.",
  "24": "Кімде-кімнің қайнаған қуаты болса, теңіздей телегей ойлы, сұңғыла, өзін-өзі әр нәрседен тия білетін, іс-әрекеті кіршіксіз таза, дхамма жолымен өмір кешкен жан болса – сол зор даңққа бөленбек.",
  "25": "Шіркін, данышпан жан күш-қайратымен, парасаттылығымен, ұстамдылығымен һәм өзін-өзі шектей білуімен ешқандай зор ағын талқандап кете алмайтын азал бөлек бір арал жасқа алсашы.",
  "26": "Надандар мен әумесерлер жеңілтектікке жақын тұрады. Ал, данышпандар салмақтылық пен парасаттылықты ең қымбат қазынасындай сақтай біледі.",
  "27": "Жеңілтектіктен аулақ болыңдар, нәпсі мен құштарлықтан сақтаныңдар, өйткені, тек салмақты және ойлы жан ғана ұлы бақытқа жете алады.",
  "28": "Мұңсыз данышпан жеңілтектікті жанына жолатпаса, даналықтың шыңына шығады да, тау басынан жазыққа жанар қадап, мұңды адамзатқа данышпанның наданға көз тастағанындай тебірене қарайды.",
  "29": "Жеңілтектердің арасындағы салмақты жан қалғып отырғандардың жанында ояу адам тұрғанындай, жүзден жалғыз қара озып келе жатқан шын жүйріктей жеке дара тұрады.",
  "30": "Махгаван құдайлардың ішінде біріншілікке салмақтылықтың арқасында ие болған. Салмақты жан мақталмақ, жеңілтек жан датталмақ.",
  "31": "Салмақтылықтан өзіне қанағат тапқан немесе жеңілтектікке жаны шоши қараған Бхикшу небір үлкен-кіші бұғауларды бұзып жанатын от тәрізді, өзіне даңғыл жол салады.",
  "32": "Салмақтылықтан өзіне қанағат тапқан немесе жеңілтектікке жаны шоши қараған Бхикшу құлауға бейім емес, өйткені, ол Нирванға жақын тұр.",
  "chap3": "Ой",
  "33": "Бейне бір садақшы мерген тәрізді данышпан адам да өз ойын тебіренген, қапаланған, жеңіл жәбірленген, өзін-өзі зорға ұстап тұрған азапты ойға қарай арнайды.",
  "34": "Бейне бір аудан шығарылып, жағаға лақтырылған балықтай жанталасқан жалынды ой тек Мараның қанды шеңгелінен сытылып шығып кетуге тырысар.",
  "35": "Көп сүрініп, мың сан жаққа бұрылып, буырқанған бұла ойды асқан сабырлылықпен ауыздықтау – игі іс. Ауыздықталған асау ой бақытқа жеткізеді.",
  "36": "Бірден түсінуге қиын, жүз сырланып, мың қырланған, жең түрініп, көп сүрінген күрделі ойын данышпан тұңғиық тереңде сақтасын. Тереңдегі тебіреністі ой бақытқа жеткізеді.",
  "37": "Алыста асқарлардан асып, жалғыз жортып жүрген жүректе ұялаған ойын асылындай аялаған асыл жан Марадан ада болмақ.",
  "38": "Кімде-кімнің ойы тұрақсыз болса, шынайы дхамманы біле алмаса кімнің сенімі құбылмалы болса, ондай жан даналыққа жетпек емес.",
  "39": "Кем-кетігі жоқ, абыржуды білмейтін, жақсылықтан да, жамандықтан да бас тартатын ой ешнәрседен жасқанбайды.",
  "40": "Осынау тәннің жүдеу жүзін аңғарып, осынау ойды берік бекініс етіп, ол даналықпен қаруланып Мараға шабуыл жасап көрсін. Ол сонда жеңіске жетіп, мақсатына қол артар болар.",
  "41": "Амал қанша! Осынау сезімсіз, пайдасыз, қураған дөңбектей дөңкиген тұл дененің жер бетінде қамшының сабындай-ақ қысқа ғұмыры қалды-ау.",
  "42": "Жауына жауы не істесе де, күншіл күншілге не істесе де, оларға ара түсетін арам ой бұлардың жайын одан арман нашарлата түспек.",
  "43": "Шешесі не істесе де, әкесі немесе басқа бір туысқаны не істесе де, әйтеуір шын пейілді адал ой жас жанның жағдайын жақсарта түсері хақ.",
  "chap4": "Гүл",
  "44": "Мынау бүкіл жерді және Яма дүниесі мен Құдайдың дүниесін кім жеңеді? Дана адамның гүлді табатыны сияқты, кім дхамманың жақсы жолын табады?",
  "45": "Мынау бүкіл жерді және Яма дүниесі мен Құдайдың дүниесін шәкірт жеңеді. Дана адамның гүлді табатыны сияқты, дхамманың жақсы жолын шәкірт табады.",
  "46": "Мынау тән бейне бір көбік сияқты екенін білетін адам, оның кіршіксіз тазалығын білетін адам, гүлмен әшекейленген Мараның оғын жұлып алған адам патшаның ажалына арналған, көзге көрінбейтін жолмен жүріп өтсін.",
  "47": "Ақылы бейне-бір кеуіп, қатып қалған қайыстай, жайнап тұрған гүлді жұлып алған адамды, тасыған су ұйықтап тұрған ағашты жұлып әкеткен адам сияқты, оның өзін де ажал келіп ұрлап әкетсін.",
  "48": "Ақылы бейне-бір кеуіп, қатып қалған қайыстай, жайнап тұрған гүлді жұлып алған, көрсеқызар сезімнің қызығына тойымсыз адамды ажал өзіне бағынышты етсін.",
  "49": "Гүлдің бояуына, иісіне ешқандай зиян келтірмей, өзіне қажетті шырынды сорып алып, ұшып кететін ара сияқты, данышпан ұстаз да ауылға дәл осылай келіп кетсінші.",
  "50": "Ол істеген не істемеген басқалардың қатесіне қарамасын, бірақ әлі істемеген не істеген өзінің қатесіне қарасын.",
  "51": "Ешқашанда іске асыруға болмайтын, кейбір адамның жақсылап айтқан сылдыр сөзі, сыртқы түрі тамаша, жайнап тұрған, бірақ жемісі де, жұпар иісі де жоқ гүл сияқты.",
  "52": "Іске асыруға болатын, кейбір адамның байсалды түрде жақсы айтқан сөзі жемісті, әрі көздің жауын алатын сан түсті және жұпар иісті гүл сияқты.",
  "53": "Бір бума гүлден көптеген гүл шеңберін жасауға болатыны сияқты, қарапайым пенде дүниеге келгеннен кейін көптеген игі істер істей алады.",
  "54": "Гүлдің жұпар иісі желге қарсы жақтан білінбейтіні сияқты, сандал ағашы мен тагар, жасмин бұталарынан да желге қарсы жақтан жұпар иісі сезілмейді. Ал, рахымшылықтың жұпар иісі желге қарсы жақтан да білініп тұрады. Жақсы адамға жүз кісілік орын бар.",
  "55": "Сандал ағашы немесе тагар, лотос немесе вассика гүлдері – ең жақсы іс, ең жақсы жұпар иіс, бұларға тең келетін дүниеде еш нәрсе жоқ.",
  "56": "Қанша дегенмен, тагар мен сандал ағашының жұпар иісі бәсеңдеу. Ал Құдайлар арасындағы игі істің жұпар иісі – ең артық жұпар иіс қой.",
  "57": "Кімде-кім шарапатты болса, әрбір істе парасаттылық танытса, өзінің кемелді білімінің арқасында еркін болса, Мара оған жететін жол таба алмайды.",
  "58": "Үлкен жолдың шетіне лақтырып тастаған қоқымның үстіне өсіп шығатын жұпар иісті, ақыл-ойды рахатқа бөлейтін лотос гүлі сияқты,",
  "59": "көрсоқырлардың отбасынан бөлініп шыққан шын мәніндегі шәкірт те өзінің даналығымен ерекшеленіп тұрады.",
  "chap5": "Ақымақтар",
  "60": "Түннің ұзақ болуы демалып, тынығатындар үшін, йоджананың ұзақ болуы шаршағандар үшін, сансараның ұзақтығы шынайы дхамманы білмейтін ақымақтар үшін қажет болмақ.",
  "61": "Ұзақ жолда сапар шеккен жан өзіне тең, не өзінен артық адам кезіктіре алмаса, ол жалғыздықты жасқанбай қарсы алғаны жөн. Ал, ақымақпен достық шынайы достық бола алмайды ғой.",
  "62": "'Ұлым менің, байлығым менің' – деп бәйек болады ақымақ адам. Ол егер түсіне білсе өзі де өзінікі емес қой. Сонда қалайша ұл оныкі болады? Байлық оныкі болады?",
  "63": "Өзінің ақымақтығын білген ақымақ данышпанға тең. Ал, өзін данышпанға теңеген ақымақ шын мәніндегі ақымақ.",
  "64": "Егер ақымақ өзінің данышпанға қатысы бар екенін өмір бойында бір сәт білсе, тіл көженің дәмін білетін қасық сыпатты болмақ.",
  "65": "Егер данышпан өзінің данышпанға қатысы бар екенін білсе, тіл көженің дәмін білгені сияқты дхаммамен тез біліспек.",
  "66": "Ақылдан жұрдай, ақымақ адам іс істеп, өзіне өзі жау болғанын білмейді де сезбейді. Ал, арам адам ісінің ащы дәмін өзі татады.",
  "67": "Артынан ащы дәмін татқызып көзді жасқа толтыратын, зар еңірететін қате іс қатерінен аулақ жүрген жөн.",
  "68": "Артынан тәтті дәмін татқызып, көңілді қуанышқа толтыратын игілікті іс жемісті де жеңісті-ау.",
  "69": "Зұлымдық, пісіп жетілгенге дейін ақымақ оны балға балайды. Кейін зұлымдық пісіп жетілгенінде ақымақ зар еңіреп, өкініш көкірегін қарс айырады.",
  "70": "Ақымақ ай сайын кус шөбінің жапырағына салып тамақ ішсе де, бәрі-бір дхамманы білетін адамның он алты бөлігінің бір бөлігіне де тұрмайды ғой.",
  "71": "Сүт бірден ұйып кетпейді емес пе, арам ойлы іс те бірден өз нәтижесін бере қоймайды, күлдің астында бықсып жатқан от тәрізді ол да ақымақтың артынан ереді.",
  "72": "Егер ақымақ адам өзінің бақытсыздығын білімімен бүркемек болса, онда сәті түсіп тұрған сыбағасынан айрылып, өзінің басын жарақаттайды.",
  "73": "Ол өзінің жағдайын пайдаланып, қолынан келместі көксеп, бхикшудың ішінде біріншілікті, монастырь билігін алуға, басқа тайпалардың арасында құрметті болуға тырысып бағады.",
  "74": "'Барлық адамдар, тіпті қаңғыбас дуаналар да осының бәрі менің істеген істерім деп ойласын. Барлық іс, барлық жағдай маған байланысты деп ойласын', - міне, ақымақтың ниеті осы, оның тоғышар тәкаббарлығы мен ниетінің топастығы күннен-күнге арта түседі.",
  "75": "Өйткені, бір жағдай байлыққа ие болуға қарай апарса, басқа бір жағдай нирванға апарады. Осыны біле отырып, бхикшу, Будданың шәкірті құрметке қуанбайды, бірақ жалғыздықты сүйеді.",
  "chap6": "Дана Адам",
  "76": "Кімде-кім өзінің кемшілігін көрсетіп айтқан дана адамды көрсе, қазынаның қайнар басын көрсеткен сол дананың соңынан ерсін. Осындайлардың соңынан еру жамандыққа емес, жақсылыққа жеткізеді.",
  "77": "Ол бізге кеңес берсін, тағлым таратсын, сұмдықтан сақтап қалсын. Ол жақсыға сүйкімді, зұлымға сұсты боп көрінетін көрікті жан ғой.",
  "78": "Жалған достың жанына ешкім де жоламасын, арам жанды ешкім де жақсыға баламасын. Жақсымен сырлас бол, жомартпен сыйлас бол.",
  "79": "Дхамманы бастан кешкен жан – бақытты болып өскен жан. Ақылы кіршіксіз кемеңгер дхамманы мақтан етер, жақсылықты жақтап өтер.",
  "80": "Диқан егінге суын салады, садақшы оғын жонады, шебер адам ағашын сайлайды, ал дана болса өзін өзі қайрайды.",
  "81": "Биік құз жартас желге мұжылмайды, дана адам мақтаса да, даттасаң да бұзылмайды.",
  "82": "Дхамманы жадына түйген дана адам қайнар бастаудың мөлдір бұлағындай тап-таза қалпында қала береді, ешқашан лайланбайды.",
  "83": "Абзал адам кез келген жағдайда да алған бетінен қайтпақ емес. Парасатты жан көп сөйлеп көпірмейді. Дана кісі күйініште де, сүйініште де бір қалпынан өзгеріп, сыр бермейді.",
  "84": "Шын данышпан өзіне де, өзгеге де не мәнсап, не байлық, не ұл бала тілемейді. Заңсыз жолмен табысқа жетуді көздемейді. Сондай саңлақтар рахымды болсын, даналықтан, даралықтан аумасын.",
  "85": "Адамдардың ішінен біразы ғана арғы жағаға өте алады. Ал, қалғандары өз жағасын таптаумен ғұмыр кешер болар.",
  "86": "Дхамманың жолын қуған, оны жақсы меңгерген жан ғана ажалды аттап өтіп, арғы жағаға жетпек.",
  "87": "Даналар ғана түнек басқан дхаммадан түңілмей өтіп, жарық айдынды жанымен аялай алар. Үйден безген, қатын-баласыз, баспанасыз, жапанды кезген бишара бекзат іңкәр болған ләззатын өзгеден тапсын.",
  "88": "Байлықтан бас тартып, биліктен безіп, өз нәпсісіне өзі тиым салған данышпан ақыл-парасатын сұрқия сұмдықтан, мәнсіз мінез-құлықтан да таза ұстасын.",
  "89": "Ешкімге жағымсынбай, тек оқымыстылыққа, білім-ғылымға сүйенген ақыл, еркіндікке жеткеніне қуанып, ешқандай арманды аңсамай жайнап жүрсе, сондай ақыл бұл дүниеде нирванға жетеді.",
  "chap7": "Архаттар",
  "90": "Әлемді кезген саяхатшының, ешнәрсені ойламайтын мұңсыздың, барлық жағынан еркін адамның, барлық бейнетті үстінен сыпырып тастай алатын жанның бойында ешқандай құштарлық дерті болмайды.",
  "91": "Дана адам жеке жүргенді жақсы көреді, оның үйде отыра беруге ықыласы жоқ. Көлін тастап ұшып кеткен аққу сияқты, ол өз мекенін тастап жеке жүре береді.",
  "92": "Дана адам өзі үшін дүние-мүлік жинамайды, оның тамаққа деген ықыласы да жоқ. Оның еншісі – ұсақ-түйек арман, тілек емес, еркіндік, азаттық. Аспандағы құстың жолы сияқты оның жолы қиын да түсініксіз.",
  "93": "Оның арман-тілегі жойылған, тамаққа да зауқы жоқ. Оның еншісі – азаттық, қандай бір тілегі, шарты да жоқ. Аспандағы құстың жолы сияқты оның жолы тайғақ кешу, ұғуға қиын.",
  "94": "Оның сезімі салиқалы, салмақты. Бейне-бір ауыздықталған ат сияқты ол. Тәкаппарлық дегенді ол білмейді, алдына қойған мақсаты да жоқ. Мұндай жанға құдайдың өзі де қызығады.",
  "95": "Ол жер сияқты сабырлы, асып-сасу, тасу дегенді білмейді. Ол бейнебір Индираның діңгегі тәрізді мығым, берік, рахымшыл. Ол жарқырап жатқан мөлдір көл сияқты. Мұндай жанда сансар да болмайды.",
  "96": "Оның ойы да парасатты және сөзі сыпайы және жігерлі.",
  "97": "Ондай адамның сенімі де жоқ, жаратылмағанды да білмейді, алданатын ермегі де жоқ, өмірдегінің бәрінен қол үзген, шын мәніндегі мархабатты адам.",
  "98": "Архаттарға ауыл да, орман да, жазық жер де, тау да, қай жерде жүрсе де оларға бәрі де ыңғайлы.",
  "99": "Оларға орманның іші де ыңғайлы. Жай адамдарға ыңғайлы, жайлы емес жердің бәрі де ыңғайлы, жайлы. Олар ешқандай сезімінің қанағаттануын тілемейді.",
  "chap8": "Мың",
  "100": "Керексіз сылдыр судан құралған мың сөзден гөрі жүрекке жетіп жататын бір сөз әлдеқайда артық.",
  "101": "Керексіз сылдыр судан құралған мың ауыз өлеңнен гөрі жүрекке жететін жалғыз жол өлең әлдеқайда артық.",
  "102": "Ешқандай мағынасыз, пайдасыз жүз ауыз өлеңді жатқа айтып тұрғаннан гөрі, естісең көңілің жай болатын жарты ауыз өлең артық.",
  "103": "Егер біреу мың жауын мың рет жеңсе, ал енді екінші біреу жалғыз өзін ғана жеңсе, соңғының жеңісі алдыңғыға қарағанда нағыз жеңімпаздың ұлы жеңісі болмақ.",
  "104": "Шынында да адамның өзін өзі жеңуі, өзіне өзі тұрақты түрде тиым сала білуі, өзін өзіне көндіре білуі басқа біреуді жеңуден әлдеқайда артық.",
  "105": "Шындығында өз ісіне берік, істің мән-жайын жетік білетін адамның жеңісін Марамен бірге Брахма да, тіпті Құдайдың өзі де жеңіліске айналдыра алмайды.",
  "106": "Кейбір адам жүз жыл бойы ай сайын мың реттен құрбандық шалсын, ал басқа біреу жалғыз сәтке болса да оған құрмет көрсетсін, бірақ өзін-өзі жетілдіре түссін. Міне, осы соңғының өзі алдыңғыдан немесе жүз жылдық құрбандық шалудан әлдеқайда артық болмақ.",
  "107": "Кейбір адам орманда жүз жыл бойы отты өшірмей сақтаса да, өзін-өзі жетілдіре түскен адам оған жалғыз сәтке құрмет көрсетсін, бәрі-бір осындай құрметтеу жүз жылдық құрбандық шалудан артық.",
  "108": "Бұл дүниеде кейбір адам жыл бойы қайырымдылық көрсетіп, шапағатын төксе де, кейде мұның өзі көк тиынға тұрмауы да мүмкін. Өмірдің әділ жолына бастаған адам бәрінен де артық.",
  "109": "Кімде-кім үлкенді сыйлай білсе, өзі жұртқа қадірлі болса төрт дхаммаға қолы жетеді. Олар: өмір, сұлулық, бақыт, қайрат.",
  "110": "Мархабатты да рахымды, өзімен өзі болып, ой тереңіне үңілген ғибратты ғұламаның бір күнгі ғұмыры бұзылған һәм бейбастақ жанның жүз жылғы ғұмырынан әлдеқайда артық.",
  "111": "Даналықтың дәриясына ден қойған һәм өзімен өзі болып, ой тереңіне үңілген ғибратты ғұламаның бір күнгі ғұмыры надан әрі нас адамның жүз жылғы ғұмырынан әлдеқайда артық.",
  "112": "Қайнаған қайраты бар қуатты адамның бір күнгі ғұмыры еріншек те босбелбеу былжырдың жүз жылғы ғұмырынан әлдеқайда артық.",
  "113": "Өмірдің басы мен соңын оймен білген өнегелі өреннің бір күнгі ғұмыры өмірдің басы мен соңын ойына да алмаған әумесердің жүз жылғы ғұмырынан көп артық.",
  "114": "Мәңгіліктің жолын көрген кемеңгердің бір күнгі ғұмыры мәңгіліктің мәнін түсіне алмаған наданның жүз жылғы ғұмырынан көп артық.",
  "115": "Жоғарғы дхамманы көзі көрген көреген жанның бір күнгі ғұмыры жоғарғы дхамманы көре алмаған көрсоқырдың ғұмырынан көп артық.",
  "chap9": "Жамандық",
  "116": "Ол біреуге жақсылық жасауға тырыссыншы. Өзінің ақыл-ойын жамандық жасаудан аулақ ұстасыншы. Біреуге жақсылық жасауға асықпаған адамның ақылы жамандықтан, яғни жамандық жасаудан ләззат алады.",
  "117": "Егер адамдарға жамандық жасаған болса, ол жамандығын басқаға да қайта-қайта жасай берсін. Бұл қылығынан ол жақсы бір үміт күтпей-ақ қойсын. Жамандық көбейген жерде қасірет тұр.",
  "118": "Егер адамдарға жақсылық жасаған болса, ол жақсылығын басқаға да қайта-қайта жасай берсін. Бұл қылығынан ол жақсы бір үміт күтсін. Жақсылық түбі – қуаныш.",
  "119": "Зұлымның өзі де, сол зұлымдығы пісіп жетілгенше, бақыт көргісі келеді. Зұлымдығы әбден пісіп жетілгенде оның көретіні – зұлымдық.",
  "120": "Тіпті ізгіліктің өзі де ізгілігі пісіп жетілгенше зұлымдықты көруі мүмкін. Ізгілігі пісіп жетілген соң оның көретіні ізгілік.",
  "121": "Зұлымдық жөнінде 'Зұлымдық маған келмейді' – деп жеңіл ойлама. Қолыңдағы ыдысыңның өзі де тамған тамшыдан су болып толады ғой. Надандар өзінің зұлымдығы қалай көбейіп кеткенін аңғармай қалады.",
  "122": "Жақсылық жөнінде: 'Жақсылық маған келмейді' – деп жеңіл ойлама. Қолыңдағы ыдысыңның өзі де тамған тамшыдан су болып толады ғой. Ақылды адам өзінің жақсылығы аздап жақсылық жасағанынан көбейгенін аңғармай қалады.",
  "123": "Байлығы көп, бірақ серігі жоқ бай адам сияқты, хауіпті жолда зұлымдықтан аулақ жүрсең, кей адамның өзі өмірінде уды көксеген сияқты болмасын.",
  "124": "Егерде қолында бірде-бір жара болмаса, уды қолымен ұстап жүре беруіне болады. Жарасы жоқ жерге у зиян тигізбейді. Кімде-кім зұлымдық жасамаған болса оған зұлымдық жоламайды.",
  "125": "Кімде-кім кіршіксіз, кінәсіз таза адамды ренжіткен болса, ондай наданға, желге қарсы лақтырған шаңның өзіңе зиян тигізетіні сияқты, оның арты жамандық болып, өзіне оралады.",
  "126": "Кейбіреулер өзінің анасының аясына оралады, зұлымдық жасағандар тамұққа, тозаққа түседі, әділдік жасағандар аспанды паналайды, арманына жете алмағандар Нирванға жетеді.",
  "127": "Ақырында зұлымдықтан арылса да, ондай жан өмірге шын сіңісіп, кірігіп кете алмаса, аспаннан да, мұхиттың ортасынан да, тіпті, жердің жарығынан да өзіне пана таба алмайды.",
  "128": "Өлімді де өз санасымен жеңе алмаса, өмірге шын сіңісіп, кірігіп кете алмаса, ондай жан аспаннан да, мұхиттың ортасынан да, тіпті жердің жарығынан да, жер бетінен де өзіне мекен таба алмайды.",
  "chap10": "Жаза",
  "129": "Жазаны ойлағанда барлық адам дірілдейді, барлық адам ажалдан қорқады. Басқаның орнына өзіңді қойып көрші. Өзің де сондай боласың. Ешкімді де өлтірме, өлтіретін жағдайға келтірме.",
  "130": "Жазаны ойлағанда барлық адам дірілдейді. Басқаның орнына өзіңді қойып көрші. Өзің де сондай боласың. Барлық адамның өмір сүргісі келеді. Ешкімді де өлтірме, өлтіретін жағдайға келтірме.",
  "131": "Кейбіреулер өзіне бақыт іздеу үшін біреуді жазалағысы келеді. Мұнымен бақыт табылмайды. Мұндай адам өлімнен кейін де бақытқа ие бола алмайды.",
  "132": "Кейбіреулер өзіне бақыт іздеу үшін біреуді жазалағысы келмейді. Мұнымен бақыт табылмайтынын біледі. Мұндай адам өлімнен кейін болса да бақытқа ие болады.",
  "133": "Ешкіммен де дөрекі түрде сөйлеспе, дөрекі сөйлесең, одан өзің де дөрекі жауап аласың. Ашулы сөз - өте ыңғайсыз. Ондай сөз өзіңе де жақсылық әкелмейді.",
  "134": "Егер сен үзілген ішектей, үнсіз қалып, тынышталсаң, сабырлық сақтасаң Нирванға жетесің. Енді сенде орынсыз ашулану, кею де болмайды.",
  "135": "Бақташының сиырды жайылымға қарай таяқпен қуатыны сияқты, қарттық та, ажал да өмір біткеннің барлығын осылай қуып отырады.",
  "136": "Надан зұлым іс істей отырып, мұны өзі білмейді де сезбейді. Ақылсыз адам өзінің ісі үшін опық жейді. Мұнысы алдындағының бәрін құртқан жанған өрт тәрізді.",
  "137": "Кімде-кім жазықсыз, бұзылмаған адамды жазаласа, ол төмендегідей он жағдайға өзі де тап болады.",
  "138": "Ондайлар мынандай он жағдайға кездесуі мүмкін: ауыр азап, денесіне зақым келуі, бітпес бейнет немесе ауру, есі ауысу,",
  "139": "күтпеген жерден кеселге ұрыну, жазықсыз жала жабу, немесе туыстарынан айрылу, немесе байлығынан айрылу, немесе үйінің өртеніп кетуі.",
  "140": "Денесі бүліне, әлсірей бастаса, ондай надан тозаққа түседі.",
  "141": "Өзінің ішіндегі күдігін жеңе алмаған пендені жалаңаш-жалпы жүру де, шашын бодыратып қоя беру де, ластық та, аштық та, дымқыл жерге жату да, тіпті орындыққа отыру да, ешнәрсе ештеңемен тазарта алмайды.",
  "142": "Оның өнебойы әшекейленген болса, бірақ ол тыныш өмір сүрсе, сабырлы, тиянақты, ұстамды, таза, кіршіксіз өмір сүрсе, тірліктегінің бәріне жаза қолдануды қаламаса, ол – брахман, ол – діндар, тақуа, ол – бхикшу болғаны.",
  "143": "Бұл дүниеден өзін қарапайымдылыққа мойын ұсындырған, қамшы салғанға бүлк етпейтін, үйреткен ат сияқты көнімпаз адам табылар ма екен?",
  "144": "Қамшыны көргенде безек қағатын, бейне бір үйретілген ат сияқты, қуатты да қажырлы болыңыз. Сенімнің, рахымшылдық пен қажымас қайраттың, үңіле ізденудің, дхамманы терең зерттеудің арқасында, Сіз ойлы да жан-жақты білімді, мінезіңіз мінсіз болып, өзіңізді жамандық біткеннің бәрінен азат етіңіз.",
  "145": "Құрылысшылар бөгетке су жібереді, мергендер алысқа атқан оғын дәл тигізеді, ағаш шеберлері ағаштан түйін түйеді, рахымшыл жандар өзін өзі дегеніне көндіреді.",
  "chap11": "Қарттық",
  "146": "Жер-жаһан жанып жатқанда мынау қай күлкі, қай қуаныш? Тұман басқан тұнжырлар, жар салып жарықты неге іздемейсіңдер?",
  "147": "Алдымен ақауға толы, әртүрлі бөлшектерден құралған, науқас, алуан ойы бар, ол ойының анық-танығы жоқ, тұрақтылығы да жоқ, әшекейленген бейнеге мұқият қарап алыңыз.",
  "148": "Мынау тозған тән дерттің жылы ұясы, опасыз, опық жегізер дүние, мынау шірік кеулеген көкірек, өйткені, өмірдің соңы - өлім.",
  "149": "Күздегі лақтырып тасталған шіріген асқабақтай жүйе-жүйесі босап кеткен қайран нар сүйектің қаңқалары-ай...",
  "150": "Сымбатты сүйектен соғылған берік бекініс – дидарлы дене; осы дененің іші қанмен әрленіп, жанмен нәрленген ғой. Бұның ішіне тағы да алдау мен арбау, қарттық пен ажал тығылған.",
  "151": "Күміспен күптелген патшаның алтын арбасы да тозады, адам денесі де тозығы жетіп, тән қартайып, ажары қайтады. Тек дхамма ғана қарттықты жақындатпай, рахымдылыққа үндейді.",
  "152": "Ақылы аз адам азған азбандай ерте қартаяды, оның денесі ғана дүрдиіп өскен, ал ақыл-ойы семіп біткен біліктілігі жетілмеген.",
  "153": "Мен үйді салған адамды іздеймін деп жүріп, сансар арқылы көп тууды көрдім, бірақ оны таба алмадым. Қайта-қайта туу – қасірет.",
  "154": "О үй салушы адам, көрдің бе?! Сен үйіңді қайта салып жатырсың. Сенің тіреуіш діңгектерің бүлінген, төбенің шатырлары да жойылған. Дүние қуған ақылың өзінің жолында арманына жетудің орнына сол арманын жойып алған.",
  "155": "Өмірін әділ жолға құрмаған адамның жас кезінде байлыққа қолы жетпейді, ал қартайған кезінде ол балығы жоқ көлге қонған құтандай мерт болады.",
  "156": "Өмірін әділ жолға құрмаған адамның жас кезінде байлыққа қолы жетпесе, қартайған кезінде бейнебір сынған садақтай, өткен кезін өкінішпен еске алып, жолда жатады.",
  "chap12": "Әр Адамдағы 'Мен'",
  "157": "Әркімнің өзінің 'мені', әрине, жақсы нәрсе. Әркім оны қырағылықпен сақтағаны дұрыс. Данышпан адам өзінің үш қорғанының бірі ретінде оған риза болуы керек.",
  "158": "Ол ең алдымен өзін тиісті жағдайға келтірсін. Содан соң басқаны үйренуіне болады. Дана адам алған жолынан аумайды.",
  "159": "Басқаны қалай үйретсе, өзі де солай үйренсін. Өзін бәріне толық көндірген адам басқаны да соған көндіре алады. Шын мәнінде өзін-өзі бәріне де көндіру қиын іс.",
  "160": "Әркімнің өзіндегі 'мен' өзінің қожасы. Оған өзінен басқа кім қожа болуы мүмкін? Ең қиын нәрсе - өзіндегі 'менді' толық тауып көндірсе, ол өзінің қожайынын тапқаны болмақ.",
  "161": "Өзінен-өзі туған, өзінен-өзі пайда болған жамандық та болады. Ал жақсылық болса, өткір алмас тасты тілетіні сияқты, надандықты да жеңеді.",
  "162": "Кімнің мінезі шәлкес болса, онда ол өзінің жауы қалағанындай іс істейді. Ондай адам сал ағашын орап, шырмап алатын манува ағашын еске түсіреді.",
  "163": "Адамға зиянды әрі жаман іс – істің жеңіліне әуес болу. Ал жақсы да пайдалы іс – қашанда ең қиын нәрсе ғой.",
  "164": "Теріс көзқарасы бар надан адам архат іліміне күдікпен қарайды. Дхаммаға байланысты өмір сүретін рахымшыл, игі ниетті адам каттхака бұтасына ұқсас, пісіп жетілген соң жемісін береді де, өзі жойылады.",
  "165": "Кей адам жамандық іс істейді де, өзін өзі қор етеді. Жамандық істемеген адамның өзі де таза болады. Тазалық пен ластық бір-бірімен байланысты. Бірін-бірі тазалай алмайды.",
  "166": "Өзінің ізгілікті ісі бола тұрып, басқаның да ізгілікті ісін жоққа шығармауы жөн. Өзінің ізгі ісін тани отырып, жоғары деңгейдегі ұлы істерге ұмтыла бергені дұрыс болмақ.",
  "chap13": "Дүние",
  "167": "Дімкәс дхамманың соңынан ілеспе! Жеңілтектікпен ғұмыр кешпе! Жалған пікірге берілме! Көп жасауға құштар болма!",
  "168": "Орныңнан тұр! Жеңілтек болма! Парасатты Дхамманың соңынан ілес! Дхамманы мүлтіксіз сақтаған жан бұл дүниеде, тіпті ол дүниеде де бақытты болмақ!",
  "169": "Парасатты дхамманың соңынан ер, бұзылғанмен бірге жүрме! Дхамманы мүлтіксіз сақтаған бұл дүниеде, тіпті ол дүниеде де бақытты болмақ!",
  "170": "Мынау дүниеге бос қуыс, бұлдыр елес деп қараған жанды ажал патшасы да көрмейді.",
  "171": "Барыңдар, анау дүйім дүниеге бейне-бір патшаның күміспен күптеген күймесіне қарағандай қараңдар! Надандар сандырақтаған жерде данышпандарға ештеңе де жоқ.",
  "172": "Алдымен жеңіл ойлы болып, артынан салиқалы салмақтылыққа ауысқан жан бейне-бір бұлт арасынан шыққан Ай секілді дүниені нұрландырып жібереді.",
  "173": "Өзінің бастан кешкен кінәсін жақсы ісімен өтеген өрен өр бейне-бір бұлт арасынан шыққан Ай секілді дүниені нұрландырып жібереді.",
  "174": "Мынау дүние көрсоқыр: бұл дүниеде кейбіреулер ғана анық көре алады. Тордан шыққан құстай аздаған адамдар ғана көкке құлаш сермеп шыға алады.",
  "175": "Аққулар күннің соқпағымен сапар шегеді, олар аспанда иддхидің көмегімен сапарға шығады. Дана адамдар Мараның жауынгерлерімен күресте жеңіп шығып, бұл дүниеден кетеді.",
  "176": "Адамдар жалған айтатындарды, ол дүниеден бас тартатындарды, бірыңғай дхамманы жек көретіндерді жеңе алмайтын болса, бұдан асқан жамандық жоқ.",
  "177": "Сараңдар шынында да құдайдың қасына жақындай алмайды, құрбандық шалдым деп мақтана алмайды. Даналар біреуге жақсылық жасап, қамқор болғанына қатты қуанады, осы қылығы үшін ол басқа дүниеде бақытты болмақ.",
  "178": "Жер бетіндегі жалғыз билеушіден, немесе аспанға ұшып барудан, бүкіл ғаламды, бүкіл дүниені жалғыз өзі билеушіден сотапатти ағымының жемісі артық.",
  "chap14": "Ағартушы",
  "179": "Бұл дүниеде жеңілген құштарлық енді бас көтермейтін, жеңісі енді жеңіліске айналмайтын, шексіз билікке, өкілдікке ие болған осынау соқпақсыз, ағартушы жанды сіз қай жолмен қайда алып бара жатырсыз?",
  "180": "Өзінің ойлаған арманынан, алған бетінен қайтпайтын, анау-мынау ұсақ-түйекке үйірлігі, құштарлығы жоқ, әбден жетілген, ағартушылық жолына мүлдем беріле түскен, жан-жақты, шексіз, осынау соқпасыз, салиқалы жанды сіз қай жолмен алып бара жатырсыз?",
  "181": "Өзі асқан дана, терең ойға түгелдей, тұтас берілген, тек өзінің азаттығынан ғана ләззат алатын осынау ағартушы жанға тіпті құдайдың өзі де қызыға қарайды.",
  "182": "Шынайы адам болу аса қиын, пенде болу да қиын, нағыз дхамманы есту де қиын, ағартушы болып туу да қиын.",
  "183": "Жамандыққа жоламау, жақсылыққа жету, өзіңнің ақыл-ойыңды таза ұстау – ағартушының ілімі міне, осылар.",
  "184": "Ұстамдылық, терең төзімділік – ең жоғарғы аскетизм, ең жоғарғы Нирвана, - дейді ағартушы адам, өйткені, басқаға қиянат жасау – тақуалық емес, біреуді өкпелету – аскет емес.",
  "185": "Біреуді масқараламау, қиянат жасамау және Практимокшаның келісімімен ұстамдылық көрсету, тамаққа қанағатшыл, жеке жүру, асқақ ойға беріле бас ию – міне, ағартушы адамның ілімі осы.",
  "186": "Тіпті аспаннан сел боп құйған алтын да нәпсіні қанағаттандыра алмайды. Нәпсіні ауру деп санайтын, одан қуаныш та көрмейтін адам ғана данышпан адам.",
  "187": "Ол аспандағы асқақ ләззаттан да қанағат ала алмайды. Толық ағартушылық жолына ұмтылған шәкірт нәпсісіне тиым салғанына қуанады.",
  "188": "Қорқыныштан үрейленген адам тау-тастан, орман ішінен, ағаш арасынан, бейіттен, барлық жерден өзіне баспана іздейді.",
  "189": "Мұндай баспана да мүлдем хауіпсіз бола алмайды, мұндай мекеннің де ешқандай артықшылығы жоқ. Мұндай мекен, баспана тапса да, ол адам барлық қасіреттен құтыла алмайды.",
  "190": "Тек Буддадан, Дхаммадан және Сангхадан пана тапса, шынайы білімді болса, сол ғана төрт шынайы шындықты көре алады.",
  "191": "Жамандық, жамандықтың арғы тегі, жамандықты жою және ізгілікті сегіз жол, осылар ғана жамандықты жоюдың жолы болмақ.",
  "192": "Міне, осындай баспаналар хауіпсіз, мұндай баспана – ең жақсысы. Осындай баспанаға қолы жеткендер барлық қайғы-қасіреттен ада болады.",
  "193": "Жақсы адамдарды іздеп табу оңай шаруа емес, ондай адам әр жерден табыла бермейді, әр жерде тумайды. Дана адам туған жердің туған-туысқандары да бақытты болмақ, гүлдене бермек.",
  "194": "Ақ ниетті адамның тууы да игілікті іс, шынайы дхамманың ғылымы да игілікті бақыт, сангхимен келісім табу да игілікті шаруа, аскетизммен келісім тауып өмір сүру де игілікті іс.",
  "195": "Кедергілерді жеңіп, қайғы мен мұңнан ада болып, осындай азаттыққа қол жеткізіп,",
  "196": "қорқыныш-үрей дегенді білмейтіндер (мейлі, ол ағартушы, не шәкірт болсын), міне осындай адамдардың құрметке лайықты істерін айтып жеткізу мүмкін емес.",
  "chap15": "Бақыт",
  "197": "О! Біз жауласпаушылар өте бақытты тұрамыз, жауласушылардың арасында тұрамыз, біз жауласпаушылар жауласушы адамдардың арасында тұрамыз.",
  "198": "О! Біз дені саулар сырқаттардың арасында өте бақытты тұрамыз, біз дені саулар сырқат адамдардың арасында тұрамыз.",
  "199": "О! Біз зарықпағандар зарыққандардың арасында өте бақытты тұрамыз; біз зарыққандар зарыққан кісілердің арасында тұрамыз.",
  "200": "О! Біз өзімізде еш нәрсе жоқ болса да, өте бақытты тұрамыз. Біз нұр сүйген құдайлар сияқты қуанышты қорек етеміз.",
  "201": "Жеңіс күншілдік туғызады. Жеңілгендерді мұң басады. Жеңістен де, жеңілістен де бастартқан сабырлы жан бақытты тұрады.",
  "202": "Құштарлықтан ыстық от болмас, күншілдіктен асқан сор болмас, тәннен артық бақытсыздық жоқ, тыныштықтан да артық бақытсыздық жоқ.",
  "203": "Аштық – асқан ауру, санкхара – ұлы зұлымдық, осының барлығын жете білетін нирвана – ұлы игілік.",
  "204": "Денсаулық – ұлы жеңіс, қанағат – ұлы байлық, сенім – ең жақсы туыс, нирвана – ұлы игілік.",
  "205": "Дхамманың тәтті ләззатын татқан адам оңашалықтың оңды екенін, сабырлылықтың сәнді екенін бастан кешіп, қорқыныш пен күнәдан ада болмақ.",
  "206": "Парасатты адамдардың жүзіне қараудың өзі бір ләззатты сәт қой, олармен бірге болу – рахат. Надандарды көрмеудің өзі бақыт.",
  "207": "Өйткені, надандармен үйір адам азаптың астында қалады, мұның өзі адамды бақытсыз етеді. Ал, ақылдылардың арасында болу – бақыт, бірге туғаныңмен кездескендей рахатты сәт кешесің.",
  "208": "Сондықтан, айдың жұлдызды аспанда сайрандайтыны сияқты ғибратты да ғұлама, көпті көрген, көпті білген салауатты да салиқалы даналармен үйір бол, солардың соңынан ер.",
  "chap16": "Жағымды Іс",
  "209": "Ұсақ-түйекпен босқа әбігер болып, өзін терең ойға арнай алмаған, өмірде алдына қойған үлкен мақсаты жоқ, болмашыдан ләззат алған адам ой үстінде, өзімен-өзі болып жүрген адамды жақтырмайды.",
  "210": "Жағымды іске де, жағымсыз іске де ешқашан түгелдей берілме. Жағымды істі ғана көріп, жағымсыз істі көрмеу – жамандыққа ұрындырады.",
  "211": "Сондықтан тек жағымды іс істеме, жағымды істен айрылу қиын екенін тағы да естен шығарма. Жағымды да, жағымсыз да ісі жоқтың дәнекері де жоқ болмақ.",
  "212": "Жағымдыдан мұң туады, жағымсыздан үрей туады. Жағымсыздан азат болғанның мұңы да жоқ. Сонда үрей қайдан келеді?",
  "213": "Бейімділіктен мұң туады, бейімділіктен үрей туады. Бейімділіктен босағанның мұңы жоқ, оған үрей қайдан келеді?",
  "214": "Әбден берілушіліктен мұң туады, әбден берілушіліктен үрей туады. Берілушіліктен босағанның мұңы жоқ, сонда үрей қайдан келеді?",
  "215": "Құштарлықтан мұң туады, құштарлықтан үрей туады. Құштарлықтан құтылғанның мұңы жоқ, сонда үрей қайдан келеді?",
  "216": "Тілектен мұң туады, тілектен қорқыныш туады. Тілектен босағанның мұңы жоқ, сонда үрей қайдан келеді?",
  "217": "Адамгершілігі мол, зерделі, дхаммаға берік, тек шындықты ғана айтатын, өзінің парызын орындайтын адамды халық сүйікті кісі деп санайды.",
  "218": "Ойы тек ләззат алу үшін ғана құрылмаған, тіл жетпестей тілек, арманы бар (бұлары тек ақылмен ғана орындалатын) адамды уддхамсота деп атайды.",
  "219": "Туыстары, достарымен тілектестері көп уақыт жоқ болып, алыстан аман-есен келген адамды қуанышпен, құшақ жая қарсы алады.",
  "220": "Туыстары алыс сапардан келген адамды қуанышпен қарсы алатыны сияқты, бұл дүниеден кеткен жақсы жанды өзінің жақсы істері қарсы алады.",
  "chap17": "Ашу, Ыза",
  "221": "Ол ашуынан бас тартсын, ол өзіне-өзі мәз болғанын қойсын, ол өзінің әр нәрсеге құштар болу қылығын жеңсін. Кімде-кім сыртқы түр мен атқа тым үйір болмаса, тым құштар болмаса, соған ешқандай бақытсыздық жоламайды.",
  "222": "Жолынан тайған арба сияқты, кімде-кім оянған ашуын тежей білсе, қалғаны тек делбені ұстап отырған адам сияқты ғана болмақ.",
  "223": "Әр адам кекшілді кек сақтамаумен, жамандықты жақсылықпен, сараңды жомарттықпен, жалған сөзді шындықпен жеңгені жөн.",
  "224": "Шындықты айту, ашуға берілмеу және өзіңде аз болса да бөлісе білубұл үш жол жұмаққа апарады.",
  "225": "Денесі көнбіс, ешкімді ренжітпейтін дана адам бір жерде тұрақтап тұрса, ондайлар азаптан ада болмақ.",
  "226": "Кімде-кім үнемі көңілді жүрсе, күндіз-түні оқыса, тек нирванға ұмтылса, ынсабы тиылады.",
  "227": "О Атула, бұл ежелден келе жатқан бір сөз ғой: 'Олар үндемей отырғанға да тиіседі, көп сөйлегенге де тиіседі, мөлшерімен сөйлегенге де тиіседі. Бұл дүниеде ол теріске шығарып, тиіспейтін, соқтықпайтын еш нәрсе жоқ.",
  "228": "Тек даттауға немесе тек мақтауға лайық адам бұрын да болмаған, қазір де болмайды, болашақта да болмақ емес.",
  "229": "Ақылды адам өзі күн сайын көзімен көріп, байқап жүрген, мінезінде артық қылығы жоқ, білімді, рахымды, мархабатты адамды ғана мадақтайды.",
  "230": "Жамбу өзенінің жағасындағы алтыннан жасалған ақшадан кім мін тауып, оны сөгер екен? Мұны тіпті құдайдың өзі де мақтайды. Брахма да оны аса дәріптейді.",
  "231": "Тәніңді күнәдан сақта, әр нәрсеге ұстамды бол, ал тәнге келер болсақ, тәніңді күнәсіз, пәк ұстай біл.",
  "232": "Сөзді кінәдан сақта, әр нәрсеге ұстамды бол, сөзге келетін болсақ, сөзіңді күнәсіз сөйлей біл.",
  "233": "Ақылыңды кінәдан сақта, әр нәрсеге ұстамды бол, ал ақылға келетін болсақ, ақылыңды күнәсіз сақтай біл.",
  "234": "Дана адамдар тәніне де ұстамды, сөзіне де ұстамды, олар шын мәнінде өмірдегі барлық жағдайда да ұстамды.",
  "chap18": "Зұлымдық",
  "235": "Сен енді бейне бір қураған жапырақ сияқтысың ғой, саған Яма жақтан адамдар келіп тұр. Сен қазір ажалдың босағасында тұрсың. Сенің қолыңда жолға алып шыққан азығың да жоқ.",
  "236": "Өзіңе өзің арал жасап ал, талмай күрес, ақылды бол. Зұлымдықтан тазарған, мінсіз сен енді қайырымдылықтың аспандағы патшалығына жетесің.",
  "237": "Сенің өмірің ақырына жетіп қалды. Сен Ямаға жақындап тұрсың. Мұнымен қоса сенің басыңда үйің жоқ, жолға алып шыққан азығың да жоқ.",
  "238": "Өзіңе арал жасап ал, қайраттан да күреске шық, ақылды бол! Зұлымдықтан өзіңді таза сақта, ешкімге қиянат жасама, кінәдан сақ бол, жастық та, қарттық та саған қайта айналып келмейді.",
  "239": "Ақылды адам күн сайын, біртіндеп өзінің үстіндегі былғанышын сілкіп, кірінен арылуы керек. Іші де, сырты да күмістей жарқырап, көз тартып тұрсын.",
  "240": "Темірді басқан тот, темірдің өзінен шықса да, оны жейді ғой. Сол сияқты өзіңнің ісің өзіңді бақытсыздыққа ұрындырады. Мұның өзі дхонға аяқ басқаның сияқты болар.",
  "241": "Егер қайталап оқып тұрмасаң жазуды кір басады, тазалап тұрмасаң үйдің іші былғанады, сұлулық еріншектіктен былғанады, өңі кетеді, сақ адам жеңілтектікке берілсе, ол да былғанады.",
  "242": "Әйелдің ерсі қылығы арам, зұлымның бергені де былғаныш.",
  "243": "Ластың ішіндегі ең лас надандықтың ласы. О Бхикшу, осы ластықтан құтыл да, лас біткеннен ада болшы.",
  "244": "Кімде-кім бейпілмінезді болса, қарғадай қағып кетуді аңдып тұрса, ақылсыз, бұзылған, жылмағай, жылпос, жағымпаз болса, сол жеңіл өмір сүреді.",
  "245": "Кімде-кім қарапайым, биязы мінезді болса, әрқашан таза жүріп, салмақты, көргенді, кінәсіз болса, оның өмір жолы ауыр болады.",
  "246": "Кімде-кім өз өмірін бүлдіріп, жалған сөз айтса, өзіне берілмеген, бойына дарымаған нәрсеге жабысса,",
  "247": "басқа біреудің әйеліне барып, күнәға батса, араққа беріліп, мас болып жүрсе, бұл дүниедегі өзінің тамырына балта шабады.",
  "248": "О адам, мынаны біл! Зұлым дхамманың шегі болмайды. Сараңдық пен дхамманың жоқ болуы ұзақ уақыт сол зұлымдыққа құл болуға мәжбүр етпесін.",
  "249": "Адамдар өзінің сенімі қанша керек етсе, соншаға келісімін береді ғой. Біреудің басқадан алған ішіп-жемін көре алмаған адам күндіз-түні өзіне өзі келе алмай, бостан-босқа дал болады.",
  "250": "Ал, кімде кім өзінің көреалмаушылық мінезін жоя білсе, оны түп-тамырымен жұлып тастай алса, сол адам күндіз-түні өзіне өзі келіп көңілі жай табады.",
  "251": "Нәпсіден артық от жоқ, ашудан артық кесел жоқ, алдаудан артық тор жоқ, арманнан артық өзен жоқ.",
  "252": "Басқаның кінәсін көру оп-оңай, ал өзіңнің кінәңді көру қиын. Өйткені, басқаның кінәсін бір нәрсенің қауызы сияқты аршып алып тастауға болады. Ал өзіңнің кінәң сүйекке біткен дерт тәрізді, оны жұлып тастай алмайсың.",
  "253": "Біреудің кінәсін ғана көре алған адам өзін өзі мазалайды, оның арман-тілегі де өсе түседі, ондай адам арман-тілегінің өсе түсуін тізгіндей алмайды.",
  "254": "Аспанда жол жоқ. Біздің сыртымызда дуана жоқ. Адамдар қуанышты қиялдан табады, татхагата қиялдан аулақ тұрады.",
  "255": "Аспанда жол жоқ. Біздің сыртымызда дуана жоқ. Мәңгілік санкхара жоқ. Оқымыстыда тұрақты еместік жоқ.",
  "chap19": "Дхамманы Сақтаушылар",
  "256": "Дхамманы өз мақсатын іске асыру үшін істі асығыс қолға алғандар сақтай алмайды. Дана адам дұрысы қайсы, бұрысы қайсы деп жан-жақты ойластырып барып іске кіріседі.",
  "257": "Ол ешкімге де күш көрсетпей, дхамма жолымен басқаларды ержүректілікпен алға бастайды. Дхамманы сақтайтын дана адамды, дхамманы сақтаушы деп атайды.",
  "258": "Ол көп сөйлегендігі үшін дана емес. Сабырлы, көреалмаушылықтан ада, қорқуды білмейтін жанды дана адам деп атайды.",
  "259": "Көп сөйлегенімен, ол дхамманы білгір адам емес, кімде-кім дхаммаға менсінбей қарамаса, тіпті ол аз оқыған адам болса да, өзінің жан-тәнімен оны сезінсе, сол адам шынында да дхамманың білгірі болмақ.",
  "260": "Басындағы шашы аппақ болғанымен, ол бәрінен үлкен емес шығар. Ол жасы келіп қалған қарт адам. Бірақ, оны 'ештеңе бітірмей қартайған адам' деп санайды.",
  "261": "Оның бойында шын мәнінде дхамма болса, күш көрсетпеу, кеуде көтермеу, өзін тежеп ұстау, бұйығы, ары кіршіксіз, ойшыл дана болса, соны үлкен адам деп таниды жұрт.",
  "262": "Қызғаншақ, күншіл, жалтарғыш, қу адам өзінің қызыл сөзділігімен, әдемі өңімен кісіні өзіне тартып тұратын сүйкімді жан бола алмайды.",
  "263": "Кімде-кім өзінің бойынан жоғарыда айтылғандай жағымсыз нәрселерді сылып тастай алса, кім ақылды болса, көреалмаушылық мінезден құтылса, сондай адамды 'жақсы кісі' деп атайды.",
  "264": "Ешкімді тыңдамайтын, өтірікші адам басындағы шашын қырып тастағанымен дәруіш бола алмайды. Өзі сараң әрі нәпсісін тия алмайтын адамнан қандай дәруіш шықпақ?",
  "265": "Кімде-кім үлкен болсын, не кішкене болсын, зұлымдықты өзіне бағындыра білсе, ондай жанды дәруіш деп атайды, өйткені, ол зұлымдықтың арам ойын тізгіндей алады ғой.",
  "266": "Басқа біреуден мейірім сұрағаны үшін бхикшу емес. Барлық дхамманы меңгеріп алып барып қана ол бхикшу бола алады.",
  "267": "Мынау дүниеде жақсылық пен жамандықтан биік тұрып, немесе кінәсіз да кіршіксіз өмір сүрсе, өзінің білімін көтерсе, осындай адамды ғана 'бхикшу' деп атайды.",
  "268": "Тірліктің тыныштық тәртібін сақтаса да, ессіз надан дана бола алмайды. 'Ақылды адам жақсыны жақтап, жаманды даттап, таразылай білсе, сол дана болмақ.",
  "269": "Бұл дүниеде осылардың бәрін ақылмен аңғара білсе, сол дана адам деңгейіне жетеді.",
  "270": "Кімде-кім кез келген тірі жанға күш көрсетсе, ол рахымсыз жан болмақ. Егер ол тірі жанның ешқайсысына күш көрсетпесе, сол ғана рахымды адам болып аталады.",
  "271": "Өзін мүлтіксіз таза сақтаумен немесе салт-дәстүрді орындаумен, немесе терең біліммен, немесе жеке отырып ойға батумен, болмаса төсекке жалғыз жатумен қарапайым адамдар жетіп жүрген архат бақытына жетуге бола ма?",
  "272": "О Бхикшу! Өзімнің нәпсімді тию арқылы жоғарыдағы көрсетілгендерге қол жеткізсем, сіз риза болар ма едіңіз?",
  "chap20": "Жол",
  "273": "Жолдың ең дұрысы – сегіз түрлі жол, шындықтың ең жақсысы – төрт түрлі сөз, дхамманың ең жақсысы – нәпсіңді тию, екі аяқтының ең үздігі – көрегендік.",
  "274": "Ең жақсы жолдар осылар. Жанарыңды тазарту үшін бұлардан басқа жол жоқ. Осы жолдарды ұстаныңдар. Бұдан басқаның бәрі – Мараның әзәзілдік жолы.",
  "275": "Осы жолдарды ұстансаңдар азап-бейнеттен құтыласыңдар. Сәтсіздіктерден қалай құтылуды білдім де, мен осы жолды Сіздерге жария еттім.",
  "276": "Сіздер өздеріңіз ұмтылуға міндеттісіздер. Жалғыз ғана ұстаз – Патхагата. Кімде-кім осы жолдан таймай, терең ойға үңілсе Мараның құрсауынан азат болады.",
  "277": "Барлық санкхаралар өтпелі нәрсе. Осыған ойлы көзбен қараған адам зұлымдыққа жиіркенішпен қарайтын болады. Тазарудың жолы осы.",
  "278": "'Барлық санкхаралар күйінішті'. Осыған ойлы көзбен қараған адам зұлымдыққа жиіркенішпен қарайтын болады. Тазарудың жолы осы.",
  "279": "'Барлық дхамма жаннан ада болған'. Осыған ойлы көзбен қараған адам зұлымдыққа жиіркене қарайтын болады. Тазарудың жолы осы.",
  "280": "Кімде-кім уақытында ұйқысынан тұрмаса, кімде-кім жастығына және қайраттылығына қарамастан еріншек болса, кімде-кімнің ойы бұлыңғыр, өзі босбелбеу болса, мұндай жалқау да сылбыр адам ақылдылыққа жол таба алмайды.",
  "281": "Айтқан сөзге көңіл қоятын, өз ойын өзі бағындыра алатын, тәнін кінәсіз ұстайтын – осы үш жолда өзінің іс-әрекетінде дұрыс сақтайтын адам даналықтың салиқалы соқпағына түсе алады.",
  "282": "Шындығында: ойдан даналық туады, ойсыздық даналықты жояды. Өмірге апаратын һәм өмірді жоятын осы екі жолды біле отырып, даналықты дамытатын жолды ойлау жөн.",
  "283": "Әйелге құштарлығы басылмаған еркек енесін емуді күтіп тұрған байлаулы бұзау тәрізді.",
  "284": "Еркектің әйелге деген құштарлығы титтей болса да басылмай тұрғанда, оның ақыл-есі де енесін емуге ұмтылған бұзаудай әйелге телінеді де тұрады.",
  "285": "Өзіңнің нәпсіңді күздікүні лотостың гүлін жұлғандай жұлып алып таста. Сабырлылық жолында Сугата көрсеткен Нирваның соңынан ергенің жөн.",
  "286": "Мен осы жерде жаңбыр кезінде де, жазда да, қыста да тұра беремін деп ойлайды надан адам. Ол хауіп-қатерді есіне де алмайды.",
  "287": "Осындай тек өзінің қамын ғана ойлайтын, ессіз жас балаға немесе малға ұқсас тілегі орындалған адамды ұйқыдағы ауылды тасқын су басып кететіні сияқты, ажал алады да кетеді.",
  "288": "Әкең де, балаң да, туған-туысқандарың да, ешкім де сені ажалдан арашалап алып қала алмайды. Ешкімнен қорғаныс таба алмассың.",
  "289": "Осы шындықты білетін ақылды адам ұстамдылық көрсетіп, Нирванға апаратын жолды тез тазартуы қажет.",
  "chap21": "Әртүрлі Жайлар",
  "290": "Егер кішкене ғана бақыт үлкен бақытқа жетуге жағдай жасаса, онда ақылды адам кішкене бақытты ойлаудан бас тартып, үлкен бақыт туралы ойлайтын болсын.",
  "291": "Кімде-кім біреуге қиянат жасау арқылы өзіне бақыт іздесе, ол көреалмаушылықтың құрсауынан босай алмайды.",
  "292": "Қазір істеуге болатын істі аяқтамай қоя тұрып, басқа бір істі бастап кететін адамдар болады. Мұндай бейпіл және дандайсып кеткен жандардың нәпсісі ырық бермей өсе түседі.",
  "293": "Бір мақсатқа жұмылдырылған ақыл, басқа істі қоя тұрып, сол бастаған ісін аяқтауға қарай бет бұрса, онда сол істі тиянақты тындырып шығуға әбден болады. Мұндай ақылды адамдардың әрнені көксеген нәпсісі тиылады.",
  "294": "Кшатри кастасындағы екі патшаны әке-шешесімен қоса өлтіріп, патшалықтарын да, ондағы адамдарды да түгел қырып, брахман тайсалмай, алған бетінен қайтпай, ештеңе болмағандай жүре береді.",
  "295": "Брахмандар кастасындағы екі патшаны және әкесі мен шешесін, бесінші етіп жолбарыс-адамды өлтіріп, брахман алған бетінен қайтпай жүре береді.",
  "296": "Бойына ұлы қырағылық дарыған Гаутаманың шәкірттері әрқашан сергек жүреді. Күндіз де, түнде де, барлық уақытта олардың ойлары Буддаға қарай ұмтылған.",
  "297": "Бойына ұлы қырағылық дарыған Гаутаманың шәкірттері әрқашан сергек жүреді. Күндіз де, түнде де, барлық уақытта олардың ойлары дхаммаға қарай ұмтылады.",
  "298": "Бойына ұлы қырағылық дарыған Гаутаманың шәкірттері әрқашан сергек жүреді. Күндіз де, түнде де, барлық уақытта олардың ойлары сангхаға ұмтылған.",
  "299": "Бойына ұлы қырағылық дарыған Гаутаманың шәкірттері әрқашан сергек жүреді. Күндіз де, түнде де, барлық уақытта олардың ойлары өзінің денесіне қарай бағытталған.",
  "300": "Бойына ұлы қырағылық дарыған Гаутаманың шәкірттері үнемі сергек жүреді. Олардың ақылы біреуге күш жұмсамайтындығы үшін қуанышқа бөленеді.",
  "301": "Бойына ұлы қырағылық дарыған Гаутаманың шәкірттері әрқашан сергек жүреді. Олардың ақыл-естері ойлануға мүмкіндік болғанына қуанады.",
  "302": "Үйренген тіршілікті тастау қиын, қуану да қиын. Үй ішіндегі өмір де қиын әрі бақытсыздық. Сенен басқамен тұру да қиын. Жиһанкез болсаң бақытсыздық артыңнан ере жүреді. Сондықтан, жиһанкез болма, бақытсыздық сенің артыңнан ермесін.",
  "303": "Өз сеніміңе берік, әрі рахымды болсаң, байлыққа, даңққа кенелесің, қай жерде жүрсең де сені құрмет тұтады.",
  "304": "Рахымды адам Гималай тауы сияқты алыстан көз тартып, нұрланып тұрады. Ал, зұлым жақыннан да көрінбейді, ол бейне бір түнде атылған оқ сияқты көзге түспейді.",
  "305": "Кімде-кім жалғыз отырса, жалғыз ұйықтаса, жалғыз қыдырса, кімде-кім іске байыпты да шебер болса, әрі өзін өзі дұрыс ұстай білсе, сол адам бейне-бір қалың орманның ішінде жүргендей қуанып жүрсін.",
  "chap22": "Тозақ",
  "306": "Кімде-кім өтірік айтса, және кімде-кім бір істі бүлдіріп алып, 'жоқ, мұны мен бүлдірген жоқпын', - деп жалтарса, сол тозаққа түседі. Өлген адамдардың барлығы, мейлі ол патша болсын, мейлі ол жай адам болсын, бірдей тең саналады.",
  "307": "Мойынын сары затпен орап жүретіндердің көпшілігі дхамма тәртібін нашар сақтайды һәм қанағатсыз келеді. Нашарлар өздерінің істерімен нашар. Олар тіпті тозақтың өзінде туғандай.",
  "308": "Елдің рахымдылық мархабатына бөленген арам пиғылды және қанағатсыз кейбіреулер бейне-бір от-жалынды жұмыр темірді жұтқан адамдарға ұқсап көрінеді.",
  "309": "Әдепсіз, басқа біреудің әйелін көксеп тұратын адам төрт нәрсеге тап болады: ұятсыз-арсыздыққа жетеді, жан тыныштығы бұзылады, жұрт оны жек көреді, тозаққа түседі.",
  "310": "Арсыздық, қатал тағдырға тап болады жоғарыдағыдай жандар, оның басында шошынған махаббат пайда болады, патша да оны қатал жазалайды. Сондықтан адамдардың басқа біреудің әйелінен аулақ жүргендері жөн.",
  "311": "Байқап ұстамасаң кейбір шөптің қолыңды кесіп кететіні сияқты, дәруіштердің өмірі де осындай болады. Өзіңді өзің дұрыс ұстамасаң тозақ сені төңіректеп жүреді.",
  "312": "Ұқыпсыз орындалған жұмыс, уақытында берілмеген қарыз, күдікті рахымшылдық – мұның барлығы адамға абырой әкелмейді.",
  "313": "Істеуге тиісті іс болса, оны көп созбай, дер кезінде орындап тастау керек. Босбелбеу жолаушы жолдың шаңын көтергеннен басқа не бітіреді.",
  "314": "Жұмыстың жаман орындалғанынан гөрі орындалмағаны артық. Өйткені, жаман орындалған жұмыс кейін ауыр азап болады. Қолға алған ісіңді сапалы орындасаң, артынан өкініші де болмайды.",
  "315": "Сыртынан да, ішінен де күзетіліп тұратын шекарадағы қала сияқты, өзіңді де берік сақта. Уақытыңды босқа өткізіп алма. Босқа өткен уақыттың арты өкініш, мұның өзі тозаққа да таяу тұрады.",
  "316": "Жалған көзқарасты ұстанатын, ұят нәрсеге тап болатын, сөйтіп, ұятқа қалатын адам теріс жолға түскен жан.",
  "317": "Жалған көзқарасты ұстанатын, қорқуға болмайтын нәрседен хауіп көретін, қорықпаса да болатын нәрседен хауіп көрмейтін адам теріс жолға түскен жан.",
  "318": "Теріс көзқарасты ұстанатын, жамандық бар жерді жамандық жоқ деп санайтын, жамандық бар жерді көрмейтін адам теріс жолға түскен адам.",
  "319": "Дұрыс көзқарасты ұстанатын, жаманды – жаман, жақсыны – жақсы деп айыра білетін адам жақсы жолға түсіп, алға қарай жүре бермек.",
  "chap23": "Піл",
  "320": "Көптеген адамдар арамза екені белгілі ғой, пілдің өзіне қарай атылған садақтың оғына төтеп беріп, шыдайтыны сияқты, мен де адамдардың масқаралап, қорлағанына төземін.",
  "321": "Үйретілгендерді ғана ұрысқа шығарады емес пе, патша да үйретілгендерді қолдайды. Үйретілген, бәріне көнген, қорлағандарға да төзген жан – ең жақсы адам.",
  "322": "Үйретілген қашарлар, Синдхтың тамаша аттары, ірі пілдер – міне осылар нағыз игілік қой. Бірақ, осының бәрінен артығы - өзіңді өзің үйретіп, ретке келтіру, не нәрсеге болса да көндіру.",
  "323": "Өйткені, өзін-өзі шектеп ұстауға көндірген және жаттығулар жасаған адам жоғарыда айтылған малдармен сонау кісі жете алмастай елге бара алмайды.",
  "324": "Дханапалака деген пілді, оның езуінен улы сілекей ағып тұрғанда ұстап тұру қиын. Байлап қойсаң ешнәрсе жемей тұрып алады, ол піл жүретін орманды аңсайды.",
  "325": "Егерде кімде-кім жалқау, мешкей, ұйқышыл, тамаққа тойып алып, қарағайлы ормандай бұйығып жата берсе, онда оның анасынан қайта-қайта туатындай ақылсыз нақұрыс болғаны.",
  "326": "Осы бір ақыл-ес бұдан бұрын өзіне ұнағанындай, өзіне жаққанындай қаңғып жүре беретін. Енді мен оны құтырған пілдерді айдап жүретін бақташыдай толық өз қолыма алдым.",
  "327": "Салиқалы салмақтылығыңды қасиеттеп сақта, ақылыңа ақау түсіре көрме. Бұрыс та былғаныш жолды пілше жойқын күшпен бұзып өтіп, дұрыс жолға түс!",
  "328": "Егер ақылды да адал досқа кездессең, жұбыңды жазбай, еңсесі көтеріліп, көңілді де ойлы, ақжарқын сол бір ғана досыңмен бар уақытыңды басыңнан бірге кеш!",
  "329": "Егер адал да әділ, ақылды да сабырлы жақсы дос таба алмасаң, жаулап алған жерінен бас тартқан тәкаббар патшаға ұқсап, жалғыз жүре бер, піл де қалың орманда жалғыздан-жалғыз жүре береді ғой.",
  "330": "Иә, жалғыз жүргеннің өзі артық. Бәрі-бір, ақымақпен дос бола алмайсың. Орманда жалғыз кезген піл сияқты жалғыз жүре бер.",
  "331": "Белгілі бір нәрсені аңсаған достар сүйкімді. Қанағат та жақсы, егер ол екі жаққа бірдей болса. Жан берер сағатта қасыңда қайырымды жандар болса, ол да жақсы. Барлық жаманшылықтан бас тарту да жақсы.",
  "332": "Бұл дүниеде ана болу қандай ғанибет, әке болу да ғанибет, дүниені кезіп жүретін дуаналық та ғанибет, сол сияқты брахмандық та қандай ғанибет.",
  "333": "Қартайғанға дейін рахымшыл болу ғанибет, сеніміңе тұрақты, тиянақты болу да жақсы іс, зұлымдық істерге ұстамдылық көрсетіп, жоламаған жөн.",
  "chap24": "Нәпсі",
  "334": "Ойсыз, алаңсыз адамның нәпсісі малува шөбі сияқты өсімтал болады. Ол - өзіне қорек іздеген маймыл тәрізді, күннен-күнге жалғаса береді.",
  "335": "Кімде-кімді дүниеге құштарлық жеңсе, жемісі өсімтал бирана шөбіне ұқсап, оның мұңы да өсе береді.",
  "336": "Кімде-кім бұл дүниеде, өте қиын болса да, өзінің нәпсісін жеңсе, біріне-бірі лотостың жапырағынан су тамшысы ұшып кететіні сияқты, оның басынан мұң да кетеді.",
  "337": "Менің сіздерге айтарым: Осы жиналып отырған бәріңе игілік тілеймін. Усирудың жұпар иісті тамырын табу үшін бирана шөбін жұлып тастайтындарың сияқты, нәпсілеріңді де тамырымен жұлып тастаңдар! Ағын қамысты ағызып кететіні сияқты, сендерді де Мара жеңе алмайды.",
  "338": "Егер тамыры әлі де берік болса, кейде шала жұлынған ағаштың өсе беретіні сияқты, нәпсіңді тия алмасаң азабың да қайта-қайта өсе береді.",
  "339": "Кім-кімде құштарлыққа, рахатқа бөленуге ұмтылған отыз алты ағын сезімі күшті болса, дұрыс көзқарастан тайған оны сол ағындар ағызып алып кетеді.",
  "340": "Барлық жерде де ағын ағып жатады. Лата өсімдігі тез жетіліп өседі. Гүлдеп жайнап тұрған латаны көрсеңіз, даналықтың көмегімен оны тамырымен жұлып тастаңыз.",
  "341": "Кейде адамды тән құштарлығының ындыны қанбай, билеп алатын сәттері болады. Рахат ләззатқа, көзсіз бақыт құшағына құмар ондай адамдар туа салысымен қартаю тағдырына тап болмақ.",
  "342": "Нәпсінің қызығына берілген адамдар қорыққан қоян сияқты өзін-өзі айналып жүгіре береді. Нәпсінің тұтқынынан шыға алмаған олар ұзақ уақыт өзінің тартатын азабына айналсоқтап қайта-қайта бара береді.",
  "343": "Нәпсінің қызығына берілген адамдар қорыққан қоян сияқты өзін-өзі айналып жүгіре береді. Сондықтан бхикшу егер өзінің құштарлық қылығын жойғысы келсе, нәпсісін бойынан қуып шықсын.",
  "344": "Ол құштарлықтан да, нәпсіден де ада болды. Өмірдің орманында күн кешті. Енді қараңызшы осы адамға: бәрінен азат болған ол қайтадан баяғыдағы бұғауына қарай өзі жүгіріп бара жатыр.",
  "345": "Данышпандар: темірден, ағаштан, бабба шөбінен жасалған бұғау өте берік деп айтпайды. Өйткені, әйелге, балаға және алтын-күмістен жасалған әсем сырғаларға деген құштарлық, ындыны қанбас нәпсі одан да күшті.",
  "346": "Данышпандар: жоғарыдан төменге тартқан бұғау өте күшті, одан босап шығу өте қиын, - дейді. Кейбіреулер сол бұғауды талқандап, нәпсіден безіп, құштарлықты да қойып, сайрандап жүр.",
  "347": "Өрмекшінің өзі тоқыған өрмекке шырмалып өлетіні сияқты, құштарлықтың қызығына желіккен жан ағып жатқан қатты ағынға тап болады. Ақылды адам ағынды жойып, жамандықтан бас тартып, нәпсісін тиып, алған бетінен қайтпай жүре береді.",
  "348": "Тіршіліктің ағынынан өте шықшы, бұрынғылардан бас тарт, болашақтан да бас тартып, осылардың екі арасындағыдан да бас тарт. Егер ақылың осылардың бәрінен азат болса, қандай жағдайда да сен қайтадан тууға және қарттыққа тап болмайсың.",
  "349": "Қашанда абыржып жүретін, әрине өте құштар, тән ләззатын ғана ойлайтын адамның нәпсісі арта түседі, сөйтіп ол өзіне өзі зиян жасайды.",
  "350": "Кімде-кім тып-тыныш жағдайда сабырлылықпен ойға шомудан қанағат тапса, үнемі ойда жүрсе, тек қана жақсылықты ойласа, сол ғана нәпсісін жеңе алады, Мараның бұғауын талқандай алады.",
  "351": "Ол кемелдікке жетті, ол ешнәрседен қорықпай, нәпсісін тия білді, кіршіксіз, кінәсіз, ол тіршіліктің бұғауын жойды, енді ол өзінің денесімен ғана жалғыз қалды.",
  "352": "Онда ешқандай тілек-талап жоқ, ол өзінің барлық берілушілік қылығынан ада болды, сөйлеуге, түсінісуге шебер, әрбір әріптің ретін біледі, мұндай адамды данышпан да ұлы жан деп атайды. Ол ақырында өзінің денесімен жалғыздан-жалғыз қалды.",
  "353": "Мен барлығын жеңдім, мен барлығын білемін, ешқашанда атымды былғамаймын. Мен барлығынан, тіпті нәпсіден де бас тарттым, еркін болдым, өзімнен өзім үйрендім, мен енді кімді ұстаз тұтамын.",
  "354": "Дхамманың сыйлығы барлық сыйлықтан асып түседі, дхамманың тәттілігі барлық тәттіден артық, дхамманың қуанышы барлық қуаныштан артық, өзінің нәпсісін жеңген адам кез-келген мұңнан арылады.",
  "355": "Байлық басқа жағаны көксеген адам емес, наданды мерт қылады. Байлық көксеген надан басқаны да, өзін де мерт етеді.",
  "356": "Арамшөп егіндікті былғайды, нәпсі адамды былғайды. Сондықтан нәпсіден тиылған адамның ісі жемісті болмақ.",
  "357": "Арамшөп егіндікті былғайды, күншілдік адамды былғайды. Сондықтан күншілдіктен құтылған жан өз іс-әрекетінде жемісті нәтижеге жетпек.",
  "358": "Арамшөп егіндікті былғайды, надандар адамды былғайды. Сондықтан надандығын жойған жанның өмірі жемісті болмақ.",
  "359": "Арамшөп егінді бүлдіреді, нәпсі адамды бүлдіреді. Сондықтан да өзінің нәпсісін тыйған адам үлкен жетістіктерге жетеді.",
  "chap25": "Бхикшулер",
  "360": "Көруге ұстамдылық – жақсы, естуге де ұстамдылық – жақсы, иіске де ұстамдылық – жақсы, тілге де ұстамдылық жақсы.",
  "361": "Тәнге ұстамдылық – жақсы, сөзге ұстамдылық – жақсы, барлық нәрсеге ұстамдылық – жақсы. Барлық жайға ұстамды болған бхикшу барлық мұңнан ада болады.",
  "362": "Қолын басқарған, аяғын басқарған, сөзін басқарған адам кемелдікке жетеді. Өйткені, іштей қуанышты, бірбеткей, басқалардан оңаша болса, міне сондай адамды бхикшу деп атайды.",
  "363": "Сөзге – ұстамды, ақылмен толғайтын, кішіпейіл, дхамманың маңызын түсіндіре білетін бхикшудің айтқан сөзі де мәнді болады.",
  "364": "Дхаммадан ләззат алатын, дхамманы мақтан ететін, дхамма туралы ғана ойлайтын, дхамманы еске сақтайтын адам – шынайы дхаммадан басқа жаққа бұрылмайды.",
  "365": "Ол өзі қол жеткізген нәрсеге астамшылықпен қарамасын, ол басқа біреуге көреалмаушылық қылық көрсетпесін. Өйткені, біреуді көреалмаған бхикшу парасаттылыққа жете алмайды.",
  "366": "Егер бхикшу өзі қол жеткізген нәрсесіне астамшылықпен қарамаса, кіршіксіз таза, шынайы өмір сүрсе, құдай оның даңқын асыра түседі, жарылқайды.",
  "367": "Кім-кімде аты мен түрін теңестіру мүлдем жоқ болса, кімде-кім ешнәрсеге мұңаймайтын болса, міне осындай адамды бхикшу деп атайды.",
  "368": "Достықта өмір сүретін, будда іліміне сенетін бхикшу бақытын, жайлы орынын тапсыншы. Сонда санкхар да тиылады.",
  "369": "О Бхикшу! Мынау кеменің ішін босат, өзіңді де ауыр жүктен босат, сен жеңіл қимылдайтын боласың. Көрсеқызарлық пен көреалмаушылықты жоя білсең, сен Нирванға жетесің.",
  "370": "Бесті босатып жібер, бестен бас тарт, бестен биік тұр! Бес бөгетке үйір болмай, оларды бұзып шыққан адамды 'ағыннан өтіп шыққан' деп атайды.",
  "371": "О бхикшу, ойлан, жеңіл ойлы болма, ойыңды сезімді қанағаттандыру ағынына айналдырма, көп нәрсе парық қыла бермейтін сені жұмыр темірді жұтуға, отты жағуға, 'Азап шеккенім-ай!' – деп жан даусыңмен айқай салуға душар етпесін.",
  "372": "Ешнәрсені білмейтін адамда ой жоқ, ойы жоқ адамда білім жоқ. Ал аты да бар, білімі де бар адам шын мәнінде Нирванаға жақын.",
  "373": "Сабырлы ақылы бар бхикшу оңаша жалғыз кетіп, таңғажайып ләззатқа бөленеді: ол дхамманы ап-анық көреді.",
  "374": "Әрбір кезде ол элементтердің пайда болуы мен қирауын толық танып, осынау мәңгілікті біледі де қуаныш пен бақытқа бөленеді.",
  "375": "Дана бхикшу үшін сезімді бақылайтын, Пратимокшаның келісімімен қанағаттану және ұстамды болу ісін іске асырудың басы, міне, осы жерде. Таза да жақсы өмірге бастайтын досыңның артынан ер.",
  "376": "Адамның мінез-құлқы өмірге һәм әділдікке бейім болсын. Ондай адам сор-бейнеттен құтылып, қуанышқа тап болады.",
  "377": "О бхикшу, вассика өзінің қураған гүлін үстінен сыпырып тастайтыны сияқты, сен де көреалмаушылық пен көрсеқызарлықтан босануға міндеттісің.",
  "378": "Сөзі салмақты, тәні тұрлаулы, ойы терең жан біртоға болып, өмірдің былық-шылығынан қашық тұрса, бхикшу деп сондай адамды айтамыз.",
  "379": "Өзіңді өзің мазала, өзіңді өзің тексер. Өзін-өзі қолға алған, өзіне өзі ие бхикшу бақытты өмір кешпек.",
  "380": "Өйткені, сен өзіңе өзің қожасың, өйткені сен өзіңе өзің жолсың. Сондықтан асауды үйреткен ер сияқты өзіңді өзің үйрет.",
  "381": "Бақытқа қолы жеткен, Будда іліміне сенген бхикшу жайлы жерге орналасып, санкхарды тоқтатсын.",
  "382": "Будда іліміне ден қойған, бұлт арасынан жарып шыққан Айдай, жас болса да дүниені жарық еткен жан бхикшу болып саналмақ.",
  "chap26": "Брахмандар",
  "383": "О брахман! Ағынды тоқтат, алға қарай бас, нәпсіні маңайыңа жолатпа! О брахман! Санкхарды жоя білсең, әлі қолға алынып жасалмағанды танисың!",
  "384": "Брахман екі дхамма арқылы басқа жағаға жетсе, онда одан білгір жанның мойнынан барлық қырсық жоғалады.",
  "385": "Мен брахман деп ол үшін ол жаға да, бұл жаға да жоқ, ол орын да, бұл орында да жоқ, еш нәрседен қорықпайтын, алдарқанушылықтан ада жанды атаймын.",
  "386": "Мен брахман деп, ойлай білетін, құштарлық дегеннің бәрінен аулақ жүретін, ұстамды, сабырлы, өз ісіне біртоға, өзінің нәпсісін жеңе білетін, жоғарғы игілікке жеткен жанды атаймын.",
  "387": "Күн күндіз жайнап тұрады, ай түнде жайнап тұрады, брахман ойға батқанда жайнап тұрады. Ал, оқымысты жан күндіз де, түнде де жайнап, жарқырап тұрады.",
  "388": "Өзінің бойынан жамандықты алып тастаған жан брахман деп аталады, тыныштықта өмір кешкен – дәруіш, өзінің бойынан былғаныш біткеннің бәрін алып тастаған жан 'тазарған жан' деп аталады.",
  "389": "Брахманды ұрып, соқпа. Бірақ брахман да өзі ренжіткен жанға көзін тігіп, сұқтана қарамасыншы. Брахманды ұру масқаралық, өзін ренжіткен жанға кек сақтау да масқара.",
  "390": "Брихман үшін өзінің ақылын жағымдылықтан сақтаудан жоғары ешнәрсе жоқ. Жойып жіберуді тілеу жоғалғанда, азап та тиылады.",
  "391": "Мен тәнімен де, сөзімен де, ойымен де ешкімге жамандық жасамайтын, осы үш нәрсеге ұстамды жанды брахман деп атаймын.",
  "392": "Мүлдем оқымысты дхамманы біз кімнен танысақ та, құрбандық оты – брахман сияқты рахымдылықпен құрметтеуіміз керек.",
  "393": "Ұйысып қалған шашымен немесе тууымен, немесе арғы тегімен брахман бола алмайды. Кімде шындық пен дхамма бар, сол бақытты, әрі сол брахман.",
  "394": "О ақымағым, мынау ұйысып қалған шашыңнан не пайда! Сенің үстіңдегі киімің мен денеңнің терісінен не пайда! Сенің ішің толған қалың жыныс, сен тек сыртыңды ғана ойлайсың.",
  "395": "Киімі шаң, былғанышты, өзі әбден арықтаған, қолының күре тамыры шығып тұрған, жападан жалғыз күн кешкен, қалың орман ішінде ой үстінде жүрген жанды мен брахман деп атаймын.",
  "396": "Мен анасынан адам болып туғаны үшін оны брахман деп атамаймын. 'Бхо деп айтатын' адамды және соған ұқсас адамды ғана солай деп атаймын. Мен ешнәрсеге үйір емес, бәрінен азат, бойында ешбір игілігі жоқ адамды брахман деп атаймын.",
  "397": "Жолындағы бөгет біткенді жоя білетін, шын мәнінде ешнәрседен қорықпайтын, ынсабын тия білетін, жалған дүниеден безген жанды мен брахман деп атаймын.",
  "398": "Мен брахман деп оқыған, көзі ашық, жолындағы бөгеттің белбеуін, қамшысын, ауыздығын шынжырмен қоса бұзған жанды атаймын.",
  "399": "Мен брахман деп төзімі күшті, ал күші - әскері, ешнәрсеге кінәлі емес, өзіне қарай айтқан сөзді, жазаны, қамауды да көтере білетін жанды атаймын.",
  "400": "Мен брахман деп ашу-ызадан ада, өзінің парызын білетін, рахымды, жеңіл жүрісі жоқ, ұстамды да байсалды, ең соңғысы өзінің денесі болатын жанды атаймын.",
  "401": "Мен брахман деп сезім ләззатына жоламайтын, лотос гүлінің астындағы су сияқты немесе біздің ұшындағы қышаның (горчицаның) дәні сияқты жанды атаймын.",
  "402": "Мен брахман деп мынау жалған дүниеден безген, үстінде лыпасы жоқ, өмірде азап-бейнетті жоя білген жанды атаймын.",
  "403": "Жоғарғы білімдарлыққа жете білген, оң мен солын айыра білген, терең ойлы данышпанды мен брахман деп атаймын.",
  "404": "Мен алдына қойған мақсат-тілегі жоқ, басында үйі де жоқ, үйі барлармен де, үйі жоқтармен де байланысы жоқ жанды атаймын.",
  "405": "Ешбір жандыны өлтірмейтін, ешкімге өлтір деп бұйырмайтын, ешбір жандыға таяқ көтермейтін, ол мейлі қорқақ, мейлі батыр болса да, міне осындайларды брахман деп атаймын.",
  "406": "Мен брахман деп толғанып-тебіренетіндердің ішінде толғанып-тебіренбейтін, таяқ көтеретіндердің ішінде ең сабырлысы, дүниеге құмарлардың ішінде мұндайдан азат жандарды атаймын.",
  "407": "Мен брахман деп құштарлық, көреалмаушылық, тәкаббарлық, екіжүзділік біздің ұшындағы қышаның (горчицаның) дәні сияқты өз бойынан оп-оңай ұшып түсетін жанды атаймын.",
  "408": "Тек шындық сөзді ғана айтатын, тағылымы мол, артық мінезі жоқ, ешкімге жала жаппайтын жанды мен брахман деп атаймын.",
  "409": "Мынау дүниедегі өзіне берілмеген нәрсенің бәрін, мейлі ол ұзын болсын, мейлі қысқа болсын, мейлі ол жақсы болсын, мейлі жаман болсын, алмайтын жанды брахман деп атаймын.",
  "410": "Мен брахман деп бұл дүниеде ешбір мақсат, тілегі жоқ, ондайлардан қол үзген, ыңғайы да жоқ жанды атаймын.",
  "411": "Мен брахман деп өзінде талап-тілек пен өзінің білімінің көмегімен күдіктенуден арылған, мәңгілікке ұюға қол жеткізген жанды атаймын.",
  "412": "Жақсылыққа да, жамандыққа да көп үйір емес, қайғы-мұң дегенді білмейтін, өзі ержүрек һәм кіршіксіз таза жүретін жанды мен брахман деп атаймын.",
  "413": "Мен брахман деп бейне-бір ай сияқты кіршіксіз таза, момын, толғанып-тебіренбейтін, тіршіліктің қуанышы бойынан сөнген жанды атаймын.",
  "414": "Мен брахман деп мынау тар жол, тайғақ кешуді басынан өткізген, басқа жағаға жүзіп өтіп шыққан, ойшыл, тілек-талап пен күдіктен азат, ешнәрсемен ісі жоқ, тыныш қана жүрген жанды атаймын.",
  "415": "Мен брахман деп құштарлықтан бас тартқан, үйсіз айдалада қаңғып жүрген, тіршіліктен баз кешкен жанды атаймын.",
  "416": "Мен брахман деп құштарлықтан бас тартқан, үй-күй, тілек-арманнан бас тартқан, тіршіліктен баз кешкен жанды атаймын.",
  "417": "Мен брахман деп адамдарға үйір болушылықты қойып, аспанға үйір болушылықты да тастап, барлық үйір болушылықтан безген жанды атаймын.",
  "418": "Мен брахман деп мынау бүкіл дүниені бір өзі жеңген, жақсы, жаманның бәрінен бас тартқан, ұстамды және өзі жаңадан туудың жолын кескен жігітті атаймын.",
  "419": "Мен брахман деп барлық жанды тіршіліктің тууы мен өлуінің мәнін білген, бір нәрсеге үйір болушылықтан азат, білімді, көзі ашық, сугата жанды атаймын.",
  "420": "Мен брахман деп өзінің жолында құдайды да, гандхарваны да, адамды да білмейтін, архата және талап-тілегі ғайып болған жанды атаймын.",
  "421": "Нәпсіге берілмеген, дүние-мүлік жинамаған, жеңімпаз да жасампаз, ұлы кемеңгер, жан-жақты жетілген жанды брахман деп атаймын.",
  "422": "Мызғымас мықты, болаттай берік, балуан білекті, арыстан жүректі, жеңімпаз да жасампаз, кемелденген кемеңгер, нәпсіге ешқашан берілмеген парасатты жанды мен брахман деп атаймын.",
  "423": "Мен өзінің бұрынғы тіршілігінен бейхабар, және аспан мен тозақты көре білетін, дана ойлы, орындауға мүмкін нәрсенің бәрін іске асырған жанды брахман деп атаймын."
};
